import React, { useState } from 'react';
import QuestionCard from './components/QuestionCard';
import ProgressBar from './components/ProgressBar';
import DataControls from './components/DataControls';

const Mongolingo = () => {
  const [currentLevel, setCurrentLevel] = useState(0);
  const [score, setScore] = useState(0);

  // Exemple de structure de donnée pour une requête
  const questions = [
    {
      id: 1,
      difficulty: "Simple",
      instruction: "Trouve tous les utilisateurs de la collection 'users' qui habitent à 'Vannes'.",
      initialCode: "db.users.find({ ... })",
      solution: "db.users.find({ city: 'Vannes' })",
      explanation: "L'opérateur find prend un objet de filtre. Ici, on cherche l'égalité simple sur le champ 'city'."
    },
    // ... les 29 autres requêtes ici
  ];

  return (
    <div className="min-h-screen bg-gray-50 p-8 font-sans">
      <header className="max-w-4xl mx-auto mb-8 flex justify-between items-center">
        <h1 className="text-3xl font-bold text-green-600">🍃 Mongolingo</h1>
        <ProgressBar current={currentLevel} total={questions.length} />
        <div className="font-bold text-lg text-orange-500">🔥 {score} pts</div>
      </header>

      <main className="max-w-4xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2">
          <QuestionCard 
            data={questions[currentLevel]} 
            onNext={() => setCurrentLevel(prev => prev + 1)}
          />
        </div>
        
        <aside className="space-y-6">
          <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200">
            <h3 className="font-bold mb-2">Structure Collection</h3>
            <pre className="text-xs bg-gray-100 p-2 rounded">
              {`{ \n  _id: ObjectId,\n  name: String,\n  city: String,\n  age: Number\n}`}
            </pre>
          </div>
          <DataControls />
        </aside>
      </main>
    </div>
  );
};

export default Mongolingo;
